package main

import "fmt"

type Node struct {
	key, value int
	pre, next  *Node
}

type LRUCache struct {
	capacity int
	cache    map[int]*Node
	dummy    *Node
}

func Constructor(capacity int) LRUCache {
	dummy := &Node{}
	dummy.pre = dummy
	dummy.next = dummy
	return LRUCache{
		capacity: capacity,
		cache:    make(map[int]*Node),
		dummy:    dummy,
	}
}

func (c *LRUCache) Get(key int) int {
	node := c.getNode(key)
	if node == nil {
		return -1
	}
	return node.value
}

func (c *LRUCache) Put(key int, value int) {
	node := c.getNode(key)
	if node != nil {
		node.value = value
		return
	}

	// 淘汰最近最少使用的节点
	if len(c.cache) >= c.capacity {
		back := c.dummy.pre
		delete(c.cache, back.key)
		c.remove(back)
	}

	newNode := &Node{key: key, value: value}
	c.cache[key] = newNode
	c.pushFront(newNode)
}

func (c *LRUCache) getNode(key int) *Node {
	node, exists := c.cache[key]
	if !exists {
		return nil
	}
	c.remove(node)
	c.pushFront(node)
	return node
}

func (c *LRUCache) remove(x *Node) {
	x.pre.next = x.next
	x.next.pre = x.pre
}

func (c *LRUCache) pushFront(x *Node) {
	oldFirst := c.dummy.next
	x.pre = c.dummy
	x.next = oldFirst
	c.dummy.next = x
	oldFirst.pre = x
}

